// Generated by Claude Opus 4.6

import React from 'react';

import styles from '@/components/AgentTerminal/index.module.css';
import { AGENT_TERMINAL_THEMES } from '@/components/AgentTerminal/themes';

const DARK_BG_COLOR = '#1e1e1e';
const LIGHT_BG_COLOR = '#fafafa';
const DARK_STATUS_COLOR = '#f0ab00';
const LIGHT_STATUS_COLOR = '#c58c00';
const ERROR_COLOR = '#c9190b';

const READY_TIMEOUT_MS = 30_000;

export interface Props {
  terminalUrl: string;
  namespace: string;
  devfileName: string;
  isDarkTheme: boolean;
  initCommand?: string;
}

interface State {
  connectionStatus: 'connecting' | 'connected' | 'error';
}

export default class AgentTerminal extends React.PureComponent<Props, State> {
  private iframeRef = React.createRef<HTMLIFrameElement>();
  private readyTimer: ReturnType<typeof setTimeout> | undefined;
  private messageHandler: ((event: MessageEvent) => void) | undefined;
  private readonly initialSrc: string;

  constructor(props: Props) {
    super(props);
    this.state = {
      connectionStatus: 'connecting',
    };
    this.initialSrc = props.terminalUrl;
  }

  componentDidMount() {
    this.messageHandler = (event: MessageEvent) => {
      if (event.data?.type === 'ttyd-ready') {
        this.onReady();
      }
    };
    window.addEventListener('message', this.messageHandler);

    this.readyTimer = setTimeout(() => {
      if (this.state.connectionStatus === 'connecting') {
        this.setState({ connectionStatus: 'error' });
      }
    }, READY_TIMEOUT_MS);
  }

  componentDidUpdate(prevProps: Props) {
    if (prevProps.isDarkTheme !== this.props.isDarkTheme) {
      this.sendThemeUpdate();
    }
  }

  componentWillUnmount() {
    if (this.readyTimer) {
      clearTimeout(this.readyTimer);
    }
    if (this.messageHandler) {
      window.removeEventListener('message', this.messageHandler);
    }
  }

  private onReady() {
    if (this.state.connectionStatus === 'connected') return;
    if (this.readyTimer) {
      clearTimeout(this.readyTimer);
    }
    this.setState({ connectionStatus: 'connected' });
    this.sendInitCommand();
  }

  private postToIframe(message: Record<string, unknown>) {
    const iframe = this.iframeRef.current;
    if (!iframe?.contentWindow) return;
    iframe.contentWindow.postMessage(message, window.location.origin);
  }

  private sendThemeUpdate() {
    const theme = this.props.isDarkTheme ? AGENT_TERMINAL_THEMES.dark : AGENT_TERMINAL_THEMES.light;
    this.postToIframe({ type: 'terminal-theme', theme });
  }

  private buildInitCommand(): string {
    const { namespace, devfileName, initCommand } = this.props;
    if (!initCommand) {
      return '';
    }
    const context =
      `'You are working in namespace "${namespace}" on a devfile named "${devfileName}". ` +
      `It is stored in a Kubernetes ConfigMap named "devfile-creator-storage" in namespace "${namespace}". ` +
      `Find the entry whose YAML content has "name: ${devfileName}"'`;
    return `${initCommand} ${context}\r`;
  }

  private sendInitCommand() {
    const command = this.buildInitCommand();
    this.postToIframe({ type: 'terminal-input', data: command });
  }

  private handleError = () => {
    this.setState({ connectionStatus: 'error' });
  };

  render(): React.ReactElement {
    const { isDarkTheme } = this.props;
    const { connectionStatus } = this.state;
    const bgColor = isDarkTheme ? DARK_BG_COLOR : LIGHT_BG_COLOR;
    const statusColor = isDarkTheme ? DARK_STATUS_COLOR : LIGHT_STATUS_COLOR;

    return (
      <div className={styles.wrapper}>
        {connectionStatus === 'connecting' && (
          <div
            className={styles.statusMessage}
            style={{ color: statusColor, backgroundColor: bgColor }}
          >
            Connecting to agent...
          </div>
        )}
        {connectionStatus === 'error' && (
          <div
            className={styles.statusMessage}
            style={{ color: ERROR_COLOR, backgroundColor: bgColor }}
          >
            Failed to load terminal
          </div>
        )}
        <iframe
          ref={this.iframeRef}
          src={this.initialSrc}
          className={`${styles.terminalContainer} ${styles.iframe}`}
          style={{ backgroundColor: bgColor }}
          title="Agent Terminal"
          onError={this.handleError}
        />
      </div>
    );
  }
}
